import React, { useState } from "react";

function CitizenDashboard() {
  const [message, setMessage] = useState("");
  const [chat, setChat] = useState([]);

  const handleSend = () => {
    if (!message) return;

    let reply = "";

    if (message.toLowerCase().includes("help") || message.toLowerCase().includes("danger")) {
      reply = "🚨 SOS ALERT SENT!";
    } else {
      reply = "✅ Complaint Registered!";
    }

    setChat([
      ...chat,
      { sender: "You", text: message },
      { sender: "AI", text: reply }
    ]);

    setMessage("");
  };

  return (
    <div style={{ padding: "20px", color: "white" }}>
      <h1>AI Civic Assistant 🚀</h1>

      <div style={{
        height: "300px",
        overflowY: "auto",
        border: "1px solid white",
        padding: "10px",
        marginBottom: "10px"
      }}>
        {chat.map((msg, i) => (
          <div key={i}>
            <b>{msg.sender}:</b> {msg.text}
          </div>
        ))}
      </div>

      <input
        value={message}
        onChange={(e) => setMessage(e.target.value)}
        placeholder="Enter complaint or SOS..."
        style={{ padding: "10px", width: "70%" }}
      />

      <button onClick={handleSend} style={{ padding: "10px" }}>
        Send
      </button>
    </div>
  );
}

export default CitizenDashboard;
